// Code node — extract text from txt file
// Automatically finds the correct binary property name
// Language: JavaScript

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const item = $input.first();

// Find all binary property names
const binaryKeys = Object.keys(item.binary ?? {});

if (binaryKeys.length === 0) {
  throw new Error('No binary data found. Check Google Drive node Binary Property setting.');
}

// Use the first binary property regardless of what it is named
const binaryKey = binaryKeys[0];
const binaryData = item.binary[binaryKey];

log('Binary key found:', binaryKey);
log('MimeType:', binaryData.mimeType);
log('FileName:', binaryData.fileName);

// Validate it is a text file
if (binaryData.mimeType && !binaryData.mimeType.includes('text')) {
  throw new Error(
    'Expected text file but got: ' + binaryData.mimeType +
    '. Convert file to .txt before saving to Google Drive.'
  );
}

// 1. Fetch the actual file content from the filesystem into a Buffer
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');

// 2. Convert that buffer to a UTF-8 string
const text = buffer.toString('utf-8');

if (!text || text.length === 0) {
  throw new Error('File decoded but text is empty');
}

log('Text length:', text.length);
log('Text preview:', text.slice(0, 200));

const fileName = item.json.name
  ?? binaryData.fileName
  ?? 'Unknown meeting';

return [{
  json: {
    fileName,
    transcriptText: text.slice(0, 8000)
  }
}];

