// Node 5 — parse OpenAI response + prepare action items for Jira
const DEBUG = $env['DEBUG'] === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const response = $input.first().json;

if (response.error) {
  throw new Error('OpenAI error: ' + response.error.message);
}
if (!response.choices || response.choices.length === 0) {
  throw new Error('No choices: ' + JSON.stringify(response).slice(0, 300));
}

const raw = response.choices[0].message.content;
const clean = raw.replace(/```json|```/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error('Invalid JSON: ' + raw.slice(0, 300));
}

// Schema validation
if (!parsed.summary || typeof parsed.summary !== 'string' || parsed.summary.trim() === '') {
  throw new Error(
    'OpenAI response missing or empty summary field.' +
    '\nRaw response: ' + raw.slice(0, 300)
  );
}

if (!parsed.action_items || !Array.isArray(parsed.action_items)) {
  throw new Error(
    'OpenAI response missing action_items array.' +
    '\nRaw response: ' + raw.slice(0, 300)
  );
}

parsed.action_items.forEach((item, i) => {
  const missingItemFields = ['description', 'owner'].filter(
    f => !item[f] || item[f].toString().trim() === ''
  );
  if (missingItemFields.length > 0) {
    // Warn but don't throw — partial action items can still be useful
    warn(`Action item[${i}] missing fields: ${missingItemFields.join(', ')}. Skipping Jira creation for this item.`);
    item._skip = true;
  }
});

// Filter out incomplete items before Jira creation
parsed.action_items = parsed.action_items.filter(item => !item._skip);



log('Meeting:', parsed.meeting_name);
log('Action items:', parsed.action_items?.length ?? 0);
log('Decisions:', parsed.decisions?.length ?? 0);

// Return one item per action item for Jira node
const actionItems = parsed.action_items ?? [];

if (actionItems.length === 0) {
  // No action items — return a placeholder so workflow continues
  return [{ json: { noActionItems: true, summary: parsed.summary } }];
}

return actionItems.map(item => ({
  json: {
    description: item.description,
    owner:       item.owner,
    due_date:    item.due_date,
    meeting:     parsed.meeting_name,
    summary:     parsed.summary,
    project:     parsed.project
  }
}));

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const response = $('Meeting Analysis OpenAI API Call').first().json;

if (response.error) {
